// Bee v3.1 — assemble ALL content URLs from WP pages + posts + product categories.
function flatten(nodeName) {
  const out = [];
  let items;
  try { items = $(nodeName).all(); } catch (e) { return out; }
  for (const it of items) {
    const j = it.json;
    if (Array.isArray(j)) out.push(...j);
    else if (j && Array.isArray(j.body)) out.push(...j.body);
    else if (j && Array.isArray(j.data)) out.push(...j.data);
    else if (j) out.push(j);
  }
  return out;
}

const pages = flatten('Get All Pages').map(p => ({...p, _wp_type: 'pages'}));
const posts = flatten('Get All Posts').map(p => ({...p, _wp_type: 'posts'}));
let cats = [];
try {
  const page1 = flatten('Get All Product Categories');
  const page2 = flatten('Get All Product Categories Page 2');
  cats = [...page1, ...page2].map(p => ({...p, _wp_type: 'product_cat'}));
} catch (e) {}

const all = [...pages, ...posts, ...cats];

const SKIP_PAGES = [103, 2];
const KILL_URL_PATTERNS = [
  /\/wp-/i, /\/feed/i, /\/cart/i, /\/checkout/i, /\/my-account/i,
  /\/privacy/i, /\/terms/i, /\/contact/i
];

const out = [];
for (const p of all) {
  if (SKIP_PAGES.includes(p.id)) continue;
  const link = p.link || '';
  if (!link) continue;
  if (KILL_URL_PATTERNS.some(re => re.test(link))) continue;
  // product_cat: skip categories with 0 products (empty pages aren't worth optimizing)
  if (p._wp_type === 'product_cat' && (p.count || 0) === 0) continue;

  out.push({
    wpId: p.id,
    url: link,
    slug: p.slug || '',
    title: (p.title && p.title.rendered) || p.name || '',  // categories use `name`
    type: p.type || p._wp_type || 'page',
    wp_type: p._wp_type,  // 'pages' | 'posts' | 'product_cat' — for REST endpoint routing
    publishedAt: p.date || null,
    excerpt: p._wp_type === 'product_cat'
      ? String(p.description || '').replace(/<[^>]+>/g, '').slice(0, 300)
      : String((p.excerpt && p.excerpt.rendered) || '').replace(/<[^>]+>/g, '').slice(0, 200),
    description: p._wp_type === 'product_cat' ? (p.description || '') : null,
    productCount: p._wp_type === 'product_cat' ? (p.count || 0) : null,
    wp_edit_url: p._wp_type === 'product_cat'
      ? 'https://liftnow.com/wp-admin/term.php?taxonomy=product_cat&tag_ID=' + p.id
      : 'https://liftnow.com/wp-admin/post.php?post=' + p.id + '&action=edit',
  });
}

return out.map(o => ({json: o}));

