// Bee v3 — per-page SEO opportunity detection (memory-conscious)
const gsc = $('GSC 90d Search Analytics').first().json;
const rows = (gsc.rows || []).slice(0, 1000);
// Filter Content Pages emits ONE item per page via map() so $input.all() = all pages
const pages = $input.all().map(i => i.json);

// Build per-URL aggregation from GSC rows
const byUrl = {};
for (const r of rows) {
  const url = r.keys?.[0];
  if (!url) continue;
  byUrl[url] = byUrl[url] || {clicks:0, impressions:0, positionSum:0, positionCount:0, queries:[]};
  const e = byUrl[url];
  e.clicks += r.clicks || 0;
  e.impressions += r.impressions || 0;
  e.positionSum += (r.position || 0) * (r.impressions || 1);
  e.positionCount += (r.impressions || 1);
  // Only keep top 8 queries per URL to control memory
  if (e.queries.length < 8) {
    e.queries.push({q: r.keys[1], pos: r.position, clicks: r.clicks, impressions: r.impressions});
  }
}

const opportunities = [];
const now = Date.now();

for (const page of pages) {
  // Try multiple URL variations (with/without trailing slash, http/https)
  const variants = [page.url, page.url.replace(/\/$/,''), page.url.replace(/^http:/, 'https:')];
  let agg = null;
  for (const v of variants) {
    if (byUrl[v]) { agg = byUrl[v]; break; }
    if (byUrl[v + '/']) { agg = byUrl[v + '/']; break; }
  }
  // Compute age
  const ageDays = page.publishedAt ? Math.floor((now - new Date(page.publishedAt).getTime())/86400000) : null;
  if (!agg) {
    // No GSC data for this page = either indexability issue OR too new
    if (ageDays && ageDays > 30) {
      opportunities.push({
        ...page,
        opportunity: 'INDEX_GAP',
        priority: 'MEDIUM',
        severity: 0,
        diagnosis: 'Page is ' + ageDays + 'd old but has 0 GSC impressions in last 90d. Likely an indexability issue (noindex, redirect, low-quality penalty, or never submitted to GSC).',
        avg_position: null, impressions_90d: 0, clicks_90d: 0,
        top_query: null
      });
    }
    continue;
  }
  const avgPos = agg.positionCount ? agg.positionSum / agg.positionCount : 0;
  const ctr = agg.impressions ? (agg.clicks / agg.impressions) : 0;
  agg.queries.sort((a,b) => b.impressions - a.impressions);
  const topQuery = (agg.queries[0] || {}).q || '';

  // Opportunity classifications
  if (avgPos >= 1 && avgPos <= 5 && ctr < 0.008 && agg.impressions > 200) {
    opportunities.push({
      ...page,
      opportunity: 'HIGH_IMP_LOW_CTR',
      priority: 'HIGH',
      severity: agg.impressions * (0.05 - ctr),  // potential clicks if CTR hit 5%
      diagnosis: 'Ranks position ' + avgPos.toFixed(1) + ' for "' + topQuery + '" with ' + agg.impressions + ' impressions but only ' + (ctr*100).toFixed(2) + '% CTR. Title or meta description likely off-target.',
      avg_position: Math.round(avgPos*10)/10, impressions_90d: agg.impressions, clicks_90d: agg.clicks,
      ctr_pct: Math.round(ctr*10000)/100,
      top_query: topQuery,
      top_queries: agg.queries.slice(0, 5)
    });
  } else if (avgPos >= 11 && avgPos <= 20 && agg.impressions > 50) {
    opportunities.push({
      ...page,
      opportunity: 'PAGE_2_STRUGGLE',
      priority: 'HIGH',
      severity: agg.impressions * 0.3,  // potential traffic if breaks page 1
      diagnosis: 'Stuck on page 2 (position ' + avgPos.toFixed(1) + ') for "' + topQuery + '" with ' + agg.impressions + ' impressions. Likely needs content depth: add H2 targeting "' + topQuery + '", expand with specific examples / numbers.',
      avg_position: Math.round(avgPos*10)/10, impressions_90d: agg.impressions, clicks_90d: agg.clicks,
      ctr_pct: Math.round(ctr*10000)/100,
      top_query: topQuery,
      top_queries: agg.queries.slice(0, 5)
    });
  } else if (avgPos >= 21 && avgPos <= 50 && agg.impressions > 20) {
    opportunities.push({
      ...page,
      opportunity: 'SLEEPING_GIANT',
      priority: 'MEDIUM',
      severity: agg.impressions * 0.1,
      diagnosis: 'Sleeping at position ' + avgPos.toFixed(1) + ' for "' + topQuery + '" — earning ' + agg.impressions + ' impressions but rarely shown. Either content depth issue or competitor strength. Needs significant content expansion.',
      avg_position: Math.round(avgPos*10)/10, impressions_90d: agg.impressions, clicks_90d: agg.clicks,
      ctr_pct: Math.round(ctr*10000)/100,
      top_query: topQuery,
      top_queries: agg.queries.slice(0, 5)
    });
  }
}

// Sort by severity (higher = bigger potential traffic win)
opportunities.sort((a,b) => b.severity - a.severity);

// Take top 5 per run
const top = opportunities.slice(0, 5);

const sd = $getWorkflowStaticData('global');
sd.lastScan = new Date().toISOString();
sd.lastOppCount = opportunities.length;

if (!top.length) {
  return [{json: {noOpportunity: true, pages_scanned: pages.length, gsc_rows: rows.length, opportunities_found: 0, note: 'No SEO opportunities crossing thresholds. Either content is performing well or impressions are still too low.'}}];
}

return top.map(o => ({json: o}));

// REDIRECT_REMAP_INJECTED v8 — Vercel redirect-check + WC slug fallback
const _ALL_ITEMS = $('Filter Content Pages').all().map(i => i.json);
const _inItem = $input.first().json || {};
const _candidateUrl = _inItem.url || '';
_inItem._redirectCheck = { attempted: false };

// P1-E HELPER GATE: hard-fail Bee if known-models is empty/errored.
const _kmResp = (() => { try { return $('Fetch Known Models').first().json; } catch(e) { return null; }})();
const _kmBrands = (_kmResp && _kmResp.brands) || null;
const _kmHealthy = _kmBrands && Object.keys(_kmBrands).length > 0 &&
                   Object.values(_kmBrands).some(b => Array.isArray(b && b.models) && b.models.length > 0);
if (!_kmHealthy) {
  _inItem.skipped = true;
  _inItem.skipReason = 'Bee bailing — Vercel /api/known-models returned no usable model data. Refusing to draft without grounding.';
  return [];
}



async function _findInPoolOrFetchCat(absDest) {
  const _norm = u => (u || '').replace(/\/+$/, '').toLowerCase();
  let match = _ALL_ITEMS.find(it => _norm(it.url) === _norm(absDest));
  if (match) return { match, fetched: false };
  // Fallback: if it's a /products/<slug>/ URL, try to fetch the WC category by slug
  const m = absDest.match(/\/products\/([^\/]+)\/?$/);
  if (m) {
    const slug = m[1];
    try {
      const cat = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://www.liftnow.com/wp-json/wp/v2/product_cat?slug=' + encodeURIComponent(slug) + '&_fields=id,link,slug,name,description,count',
        json: true,
        timeout: 8000,
        ignoreHttpStatusErrors: true,
      });
      if (Array.isArray(cat) && cat.length > 0) {
        const c = cat[0];
        return {
          match: {
            wpId: c.id,
            url: c.link,
            slug: c.slug,
            title: c.name || '',
            wp_type: 'product_cat',
            description: c.description || '',
            productCount: c.count || 0,
            wp_edit_url: 'https://liftnow.com/wp-admin/term.php?taxonomy=product_cat&tag_ID=' + c.id,
          },
          fetched: true,
        };
      }
    } catch (e) {}
  }
  return { match: null, fetched: false };
}

if (_candidateUrl) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://bid-iq-neon.vercel.app/api/check-redirect?url=' + encodeURIComponent(_candidateUrl),
      json: true,
      timeout: 10000,
      ignoreHttpStatusErrors: true,
    });
    _inItem._redirectCheck = { attempted: true, candidateUrl: _candidateUrl, ...res };
    if (res && res.ok && res.redirected && res.location) {
      const _absDest = res.location.startsWith('http') ? res.location : ('https://liftnow.com' + res.location);
      _inItem._redirectCheck.destination = _absDest;
      const lookup = await _findInPoolOrFetchCat.call(this, _absDest);
      _inItem._redirectCheck.matchedInPool = !!lookup.match && !lookup.fetched;
      _inItem._redirectCheck.matchedViaSlugFetch = !!lookup.match && lookup.fetched;
      if (lookup.match) {
        const _match = lookup.match;
        _inItem._originalRedirected = { from: _candidateUrl, to: _absDest, original_wpId: _inItem.wpId };
        _inItem.wpId = _match.wpId;
        _inItem.url = _match.url;
        _inItem.slug = _match.slug;
        _inItem.title = _match.title || _inItem.title;
        _inItem.wp_type = _match.wp_type;
        _inItem.wp_edit_url = _match.wp_edit_url;
        if (_match.wp_type === 'product_cat') {
          _inItem.current_description = _match.description || '';
          _inItem.productCount = _match.productCount || 0;
        }
        _inItem._remappedToDestination = true;
      } else {
        // P1-E: bail early instead of wasting a draft on an untracked page.
        _inItem.skipped = true;
        _inItem.skipReason = 'Bee bailing — redirected to non-tracked destination: ' + _absDest;
        return [];
      }
    }
  } catch (e) {
    _inItem._redirectCheck = { attempted: true, candidateUrl: _candidateUrl, ok: false, error: String(e.message || e).slice(0, 200) };
    _inItem.skipped = true;
    _inItem.skipReason = 'Bee bailing — Vercel /api/check-redirect helper threw: ' + String(e.message || e).slice(0, 150);
    return [];
  }
}
// END REDIRECT_REMAP_INJECTED v8
// KB_MODELS_INJECTED — inject authoritative product model list into LLM
// system prompt so it can't hallucinate non-existent BendPak/Challenger/PKS models.
try {
  const km = $('Fetch Known Models').first().json;
  if (km && km.ok && km.brands) {
    const sections = [];
    for (const [brand, info] of Object.entries(km.brands)) {
      const list = (info && info.models) || [];
      if (list.length === 0) continue;
      // Cap each brand at first 100 models to keep prompt tokens reasonable
      const capped = list.slice(0, 100);
      sections.push('  ' + brand.toUpperCase() + ' (' + list.length + ' total): ' + capped.join(', '));
    }
    if (sections.length > 0) {
      _inItem._kbModelsBlock = '\n\n# AUTHORITATIVE PRODUCT MODELS — Liftnow KB (' + new Date().toISOString().slice(0,10) + ')\n\nLiftnow sells exactly these model numbers. If you reference a product, use ONE OF THESE EXACT NAMES. Do NOT invent. If your draft would mention a model not in this list, either pick the closest real one or omit the model number entirely.\n\n' + sections.join('\n') + '\n\nHARD RULE: any model name you write must appear character-for-character in the list above. If unsure, refer to the lift category generically ("two-post asymmetric", "four-post heavy-duty") instead of guessing a specific model.';
    }
  }
} catch (e) {
  _inItem._kbModelsBlock = '';
}
// END KB_MODELS_INJECTED










const inputItem = $input.first().json || {};
const oppOriginal = inputItem.opp || {};
const candidateUrl = oppOriginal.url || '';
if (candidateUrl) {
  const dest = await checkRedirect.call(this, candidateUrl);
  if (dest) {
    // Resolve relative dest to absolute
    const absDest = dest.startsWith('http') ? dest : ('https://liftnow.com' + dest);
    // Try to find a candidate item with matching link (normalize trailing slash)
    const norm = u => (u || '').replace(/\/$/, '').toLowerCase();
    const match = ALL_ITEMS.find(it => norm(it.url) === norm(absDest));
    if (match) {
      // Remap: replace opp's wp target with destination's
      oppOriginal._originalRedirected = {from: candidateUrl, to: absDest, original_wpId: oppOriginal.wpId};
      oppOriginal.wpId = match.wpId;
      oppOriginal.url = match.url;
      oppOriginal.slug = match.slug;
      oppOriginal.title = match.title || oppOriginal.title;
      oppOriginal.wp_type = match.wp_type;
      oppOriginal.wp_edit_url = match.wp_edit_url;
      // For categories, expose the existing description so LLM knows what's there
      if (match.wp_type === 'product_cat') {
        oppOriginal.current_description = match.description || '';
      }
      inputItem.opp = oppOriginal;
      inputItem._remappedToDestination = true;
    } else {
      // Destination not in our pool — skip this opp entirely
      inputItem.skipped = true;
      inputItem.skipReason = 'redirected to non-tracked destination: ' + absDest;
      return [{json: inputItem}];
    }
  }
}
// Bee v3 — build LLM payload for on-page fix
const VOICE = "# VOICE \u2014 PAUL STERN ARTICLE VOICE (mandatory for SEO drafts)\n\nYou are drafting on-page SEO fixes for a Liftnow content page. The page will be PATCHed in WordPress on Paul's approval. Match Paul's voice.\n\n## ALWAYS\n- Brand: \"Liftnow\" (never \"LiftNow\" or \"LIFTNOW\")\n- First-person plural \"we\" for Liftnow actions, \"you\" for reader\n- Hedged contract promises: \"typically\", \"depending on the contract\", \"confirmed on the quote\"\n- Industry shorthand without explanation (GVWR, Class 8, frame engagement, rolling jacks)\n- Specific numbers always\n- Active voice\n\n## NEVER\n- \"Revolutionary\", \"industry-leading\", \"best-in-class\", \"cutting-edge\"\n- \"In today's fast-paced fleet management world...\"\n- Competitor brand names as Liftnow products (no Mohawk, Stertil-Koni, Rotary, Ari-Hetra, Hunter, Snap-on, Whip, Challenger)\n- Absolute promises (\"always\", \"every\")\n- \"ALI-certified inspection\" for Liftnow's service (we subcontract)\n- \"We don't subcontract\" (false)\n- \"45+ states\" \u2014 use \"all 50 states\"\n\n## SEO-SPECIFIC\n- Titles: 55-60 chars max. Include target keyword in first 3 words when natural.\n- Meta description: 150-160 chars max. Include target keyword + concrete value proposition. End with implicit CTA.\n- H2 sections: phrase as a question or specific claim the target keyword would search for.\n- Body additions: 150-400 words of new content. Specific examples, numbers, scenarios.\n\n# IDENTITY — HARD RULE (overrides any conflicting voice instruction below)\n\nYou are writing AS LIFTNOW. Liftnow is a Sourcewell-contracted commercial vehicle lift DEALER + installer. Liftnow is NOT a fleet operator, NOT a customer, NOT an end user of the lifts. Liftnow SELLS and INSTALLS the lifts to government fleets, transit agencies, school districts, etc.\n\n## NEVER position Liftnow as a customer\n- ❌ \"We just took delivery of a four-post mobile column set for our 47-truck fleet\"\n- ❌ \"We installed a CL20 in our shop last week\"\n- ❌ \"Our maintenance team uses...\"\n- ❌ \"Our fleet runs...\"\n- ❌ \"Since we switched to BendPak lifts...\"\n- ❌ Any first-person \"we bought / we own / we operate / we maintain\" framing where \"we\" = a fleet that uses lifts.\n\n## ALWAYS position Liftnow as the dealer/installer\n- ✅ \"We spec'd a four-post mobile column set for a 47-truck municipal fleet last quarter — here's the breakdown.\"\n- ✅ \"From the Liftnow shop floor: across maybe 30 transit-bus installs in the past 18 months, the consistent friction point is column spacing on older depot bays.\"\n- ✅ \"When a customer asks us about CL20 vs CL12A, the real spec gap is...\"\n- ✅ \"Across the Liftnow installer network, the most common failure mode is...\"\n- ✅ \"Liftnow's been quoting under Sourcewell 121223-LFT since [date]; the contract field that catches buyers off-guard is...\"\n\n## Disclosure\nThe reader should understand within the first 2 sentences that this is from a vendor sharing what they've learned, not from a fleet operator describing their own setup. If you can't write the piece without making Liftnow sound like a customer, RETURN skip:true.\n\n## Platform-specific\n- LinkedIn: byline \"By Paul Stern, VP Public Sector Sales — Liftnow\" makes the dealer relationship clear; voice can still be first-person about Liftnow's experience.\n- Reddit: even MORE careful — reddit users downvote covert advertising. Sign reply/post with \"— Paul, Liftnow\" or open with \"Liftnow rep here, but adding actual content vs sales pitch:\". Be honest about who you are; redditors respect honesty more than coverage.\n- Blog/article: byline + clear \"Liftnow's experience across N installs\" framing in the opening.\n\n## Test before submitting\nRe-read the draft. Ask: \"Would a reasonable reader think the author is a fleet operator who bought lifts?\" If yes, REWRITE entirely.\n\n\n# PRICING — HARD RULE (additional to identity rule above)\nNEVER include pricing estimates, dollar figures, contract pricing, \"starts at $X\", or \"$X-$Y range\" in any public post. Pricing has too many config-specific variables; posting a number anchors readers on figures that won't match their actual quote. Acceptable hedges:\n- \"confirmed on the quote\"\n- \"depends on your bay dimensions and vehicle list\"\n- \"pricing varies by Sourcewell discount tier and configuration\"\n- \"send your vehicle list + bay dimensions to gov@liftnow.com for a quote\"\n\nIf your draft includes any specific dollar figure for lift purchase, install, or contract cost, REMOVE it before posting. Even comparative pricing (\"Liftnow's typically 15-20% less than X\") is banned in public copy.\n";
const item = $input.first().json;
const opp = item.opportunity || '';
const topQueries = (item.top_queries || []).slice(0, 5).map(q => `  - "${q.q}" (pos ${q.pos.toFixed(1)}, ${q.impressions} imp, ${q.clicks} clicks)`).join("\n");

