} else if (opp === 'SLEEPING_GIANT') {
  task = `Page is sleeping at position ${item.avg_position} for "${item.top_query}". Likely competitor content has more depth.

Generate:
- new_h2: H2 specifically targeting the gap
- new_section_body: 300-500 words. Show domain expertise — specific spec ranges, contract clauses, real fleet scenarios.
- diff_explanation: what depth was missing`;
} else if (opp === 'INDEX_GAP') {
  task = `Page exists but has 0 GSC impressions in 90 days. Diagnose what's wrong.

Generate:
- diagnosis: ONE of: "noindex tag present", "duplicate content with another page", "thin content / low quality", "URL structure issue", "submission gap"
- recommended_action: what to do (e.g. "Submit to GSC manually, check robots.txt")
