try {
  const km = $('Fetch Known Models').first().json;
  if (km && km.ok && km.brands) {
    const knownSet = new Set();
    for (const info of Object.values(km.brands)) {
      for (const m of (info.models || [])) knownSet.add(String(m).toUpperCase());
    }
    if (knownSet.size > 0) {
      const body = String((newSection || '') + ' ' + (newTitle || '') + ' ' + (newExcerpt || ''));
      // Find model-looking strings: 2-6 letter prefix + digits + optional suffix
      const matches = body.match(/\b[A-Z][A-Z0-9]{0,5}-?\d{1,5}[A-Z0-9\-]{0,10}\b/g) || [];
      const violators = [];
      for (const m of matches) {
        const up = m.toUpperCase();
        // Skip obvious non-models
        if (up.length < 3 || up.length > 25) continue;
        if (/^\d+$/.test(up)) continue;
