    const j = it.json;
    if (Array.isArray(j)) out.push(...j);
    else if (j && Array.isArray(j.body)) out.push(...j.body);
    else if (j && Array.isArray(j.data)) out.push(...j.data);
    else if (j) out.push(j);
  }
  return out;
}

