// Bee v3 — per-page SEO opportunity detection (memory-conscious)
const gsc = $('GSC 90d Search Analytics').first().json;
const rows = (gsc.rows || []).slice(0, 1000);
// Filter Content Pages emits ONE item per page via map() so $input.all() = all pages
const pages = $input.all().map(i => i.json);

// Build per-URL aggregation from GSC rows
const byUrl = {};
for (const r of rows) {
  const url = r.keys?.[0];
  if (!url) continue;
  byUrl[url] = byUrl[url] || {clicks:0, impressions:0, positionSum:0, positionCount:0, queries:[]};
  const e = byUrl[url];
  e.clicks += r.clicks || 0;
  e.impressions += r.impressions || 0;
  e.positionSum += (r.position || 0) * (r.impressions || 1);
  e.positionCount += (r.impressions || 1);
  // Only keep top 8 queries per URL to control memory
  if (e.queries.length < 8) {
    e.queries.push({q: r.keys[1], pos: r.position, clicks: r.clicks, impressions: r.impressions});
  }
}

const opportunities = [];
const now = Date.now();

for (const page of pages) {
  // Try multiple URL variations (with/without trailing slash, http/https)
  const variants = [page.url, page.url.replace(/\/$/,''), page.url.replace(/^http:/, 'https:')];
  let agg = null;
  for (const v of variants) {
    if (byUrl[v]) { agg = byUrl[v]; break; }
    if (byUrl[v + '/']) { agg = byUrl[v + '/']; break; }
  }
  // Compute age
  const ageDays = page.publishedAt ? Math.floor((now - new Date(page.publishedAt).getTime())/86400000) : null;
  if (!agg) {
    // No GSC data for this page = either indexability issue OR too new
    if (ageDays && ageDays > 30) {
      opportunities.push({
        ...page,
        opportunity: 'INDEX_GAP',
        priority: 'MEDIUM',
        severity: 0,
        diagnosis: 'Page is ' + ageDays + 'd old but has 0 GSC impressions in last 90d. Likely an indexability issue (noindex, redirect, low-quality penalty, or never submitted to GSC).',
        avg_position: null, impressions_90d: 0, clicks_90d: 0,
        top_query: null
      });
    }
    continue;
  }
  const avgPos = agg.positionCount ? agg.positionSum / agg.positionCount : 0;
  const ctr = agg.impressions ? (agg.clicks / agg.impressions) : 0;
  agg.queries.sort((a,b) => b.impressions - a.impressions);
  const topQuery = (agg.queries[0] || {}).q || '';

  // Opportunity classifications
  if (avgPos >= 1 && avgPos <= 5 && ctr < 0.008 && agg.impressions > 200) {
    opportunities.push({
      ...page,
      opportunity: 'HIGH_IMP_LOW_CTR',
      priority: 'HIGH',
      severity: agg.impressions * (0.05 - ctr),  // potential clicks if CTR hit 5%
      diagnosis: 'Ranks position ' + avgPos.toFixed(1) + ' for "' + topQuery + '" with ' + agg.impressions + ' impressions but only ' + (ctr*100).toFixed(2) + '% CTR. Title or meta description likely off-target.',
      avg_position: Math.round(avgPos*10)/10, impressions_90d: agg.impressions, clicks_90d: agg.clicks,
      ctr_pct: Math.round(ctr*10000)/100,
      top_query: topQuery,
      top_queries: agg.queries.slice(0, 5)
    });
  } else if (avgPos >= 11 && avgPos <= 20 && agg.impressions > 50) {
    opportunities.push({
      ...page,
      opportunity: 'PAGE_2_STRUGGLE',
      priority: 'HIGH',
      severity: agg.impressions * 0.3,  // potential traffic if breaks page 1
      diagnosis: 'Stuck on page 2 (position ' + avgPos.toFixed(1) + ') for "' + topQuery + '" with ' + agg.impressions + ' impressions. Likely needs content depth: add H2 targeting "' + topQuery + '", expand with specific examples / numbers.',
      avg_position: Math.round(avgPos*10)/10, impressions_90d: agg.impressions, clicks_90d: agg.clicks,
      ctr_pct: Math.round(ctr*10000)/100,
      top_query: topQuery,
      top_queries: agg.queries.slice(0, 5)
    });
  } else if (avgPos >= 21 && avgPos <= 50 && agg.impressions > 20) {
    opportunities.push({
      ...page,
      opportunity: 'SLEEPING_GIANT',
      priority: 'MEDIUM',
      severity: agg.impressions * 0.1,
      diagnosis: 'Sleeping at position ' + avgPos.toFixed(1) + ' for "' + topQuery + '" — earning ' + agg.impressions + ' impressions but rarely shown. Either content depth issue or competitor strength. Needs significant content expansion.',
      avg_position: Math.round(avgPos*10)/10, impressions_90d: agg.impressions, clicks_90d: agg.clicks,
      ctr_pct: Math.round(ctr*10000)/100,
      top_query: topQuery,
      top_queries: agg.queries.slice(0, 5)
    });
  }
}

// Sort by severity (higher = bigger potential traffic win)
opportunities.sort((a,b) => b.severity - a.severity);

// Take top 5 per run
const top = opportunities.slice(0, 5);

const sd = $getWorkflowStaticData('global');
sd.lastScan = new Date().toISOString();
sd.lastOppCount = opportunities.length;

if (!top.length) {
  return [{json: {noOpportunity: true, pages_scanned: pages.length, gsc_rows: rows.length, opportunities_found: 0, note: 'No SEO opportunities crossing thresholds. Either content is performing well or impressions are still too low.'}}];
}

return top.map(o => ({json: o}));

